mapper.select:
SELECT o.id, o.order_no AS orderNo, o.contact_name AS userName, o.contact_phone AS userPhone, CONCAT_WS(' ', cm.brand_name, cm.series_name) AS vehicleName, c.plate_number AS plate, CONCAT( DATE_FORMAT(o.rent_start_time, '%Y-%m-%d %H:%i'), ' ~ ', DATE_FORMAT(o.rent_end_time, '%Y-%m-%d %H:%i') ) AS rentalPeriod, o.total_days AS days, o.total_amount AS amount, o.status FROM `order` o LEFT JOIN car_info c ON o.car_id = c.car_id LEFT JOIN car_models cm ON c.model_id = cm.model_id
AND o.order_no LIKE CONCAT('%', #{query.orderNo}, '%')
AND (o.contact_name LIKE CONCAT('%', #{query.userInfo}, '%') OR o.contact_phone LIKE CONCAT('%', #{query.userInfo}, '%'))
AND o.status = #{query.status}
AND DATE(o.create_time) >= #{query.startDate}
AND DATE(o.create_time) <= #{query.endDate}
ORDER BY o.create_time DESC
